class Solution{
public:
    int maxSubarraySum(vector<int>& nums) {
        if (nums.size() == 0) return 0;
        int max_sum = nums[0];
        int current_sum = 0;

        for (int i = 1; i < nums.size(); i++) {
            current_sum = max(nums[i], current_sum + nums[i]);
            max_sum = max(max_sum, current_sum);
        }
        return max_sum;
    }
};
